class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n
        self.components = n      # track component count

    def find(self, x):           # O(α(N)) amortized
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])  # path compression
        return self.parent[x]

    def union(self, x, y) -> bool:
        px, py = self.find(x), self.find(y)
        if px == py: return False  # already connected — would form cycle
        # Union by rank: attach smaller tree to larger
        if self.rank[px] < self.rank[py]: px, py = py, px
        self.parent[py] = px
        if self.rank[px] == self.rank[py]:
            self.rank[px] += 1
        self.components -= 1
        return True

    def connected(self, x, y) -> bool:
        return self.find(x) == self.find(y)

# Number of Connected Components in Undirected Graph
def count_components(n, edges):
    uf = UnionFind(n)
    for u, v in edges:
        uf.union(u, v)
    return uf.components

# Redundant Connection (cycle detection)
def find_redundant(edges):
    uf = UnionFind(len(edges) + 1)
    for u, v in edges:
        if not uf.union(u, v):  # union failed → already connected → cycle
            return [u, v]

# Cycle detection in directed graph
def has_cycle_directed(n, edges):
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)

    # 0=unvisited, 1=in stack, 2=done
    state = [0] * n

    def dfs(node):
        state[node] = 1  # in stack
        for neighbor in graph[node]:
            if state[neighbor] == 1: return True   # back edge = cycle
            if state[neighbor] == 0 and dfs(neighbor): return True
        state[node] = 2  # done
        return False

    return any(dfs(i) for i in range(n) if state[i] == 0)

# Cycle detection in undirected graph (DFS)
def has_cycle_undirected(n, edges):
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v); graph[v].append(u)
    visited = set()

    def dfs(node, parent):
        visited.add(node)
        for neighbor in graph[node]:
            if neighbor not in visited:
                if dfs(neighbor, node): return True
            elif neighbor != parent:   # back edge (not to parent)
                return True
        return False

    return any(dfs(i, -1) for i in range(n) if i not in visited)

# BSP superstep skeleton (conceptual)
def pregel_superstep(vertices, edges, messages_in):
    """
    One superstep of Pregel computation.
    vertices: dict {vid: state}
    edges: dict {vid: [neighbor_vid, ...]}
    messages_in: dict {vid: [msg, ...]} from previous superstep
    Returns: (updated_vertices, messages_out)
    """
    messages_out = {}
    for vid, state in vertices.items():
        incoming = messages_in.get(vid, [])
        # Compute new state and outgoing messages
        new_state, msgs = compute(vid, state, incoming, edges[vid])
        vertices[vid] = new_state
        for neighbor, msg in zip(edges[vid], msgs):
            messages_out.setdefault(neighbor, []).append(msg)
    # Barrier: all workers complete before next superstep
    return vertices, messages_out

# Example: PageRank vertex compute function
def compute(vid, state, incoming, out_edges):
    DAMPING = 0.85
    rank_sum = sum(incoming) if incoming else 0
    new_rank = (1 - DAMPING) + DAMPING * rank_sum
    if out_edges:
        msg_new = new_rank / len(out_edges)
        out_msgs = [msg_new] * len(out_edges)
    else:
        out_msgs = []
    return new_rank, out_msgs
